#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;

const int N=3e5+10,B=1000,M=560;

struct Seg{
	int l,r,k;
}seg[N]; 

int n,m,a[N],ans[N],len=550,lmn[M][M],rmn[M][M],f[M][10];
int t[N<<2];
pair<int,int> p[N];
vector<int> v[N],ask;

inline int cal(int x){
    return (x-1)/len+1;
}

void build(int cur,int l,int r,int k){
    if(l==r){
        t[cur]=a[l]%k;
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid,k);
    build(cur*2+1,mid+1,r,k);
    t[cur]=min(t[cur*2],t[cur*2+1]);
}

int query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    int mid=l+r>>1,res=1e9;
    if(x<=mid)
        res=min(res,query(cur*2,l,mid,x,y));
    if(y>mid)
        res=min(res,query(cur*2+1,mid+1,r,x,y));
    return res;
}

inline void add(int x){
    int p=cal(x);
    for(int i=x;i<=p*len;i++)
        lmn[p][i-(p-1)*len]=a[x];
    for(int i=x;i>(p-1)*len;i--)
        rmn[p][i-(p-1)*len]=a[x];
    for(int i=0;i<10;i++)
        for(int j=p;j<=min(cal(n),p+(1<<i)-1);j++)
            f[j][i]=a[x];
}

inline int RMQ(int l,int r){
    int len=log2(r-l+1);
    return min(f[r][len],f[l+(1<<len)-1][len]);
}

inline int Ask(int l,int r){
    int p=cal(l),q=cal(r),res;
    res=min(rmn[p][l-(p-1)*len],lmn[q][r-(q-1)*len]);
    if(p+1<q)
        res=min(res,RMQ(p+1,q-1));
    return res;
}

bool cmp(int x,int y){
	return x/N*seg[x%N].k>y/N*seg[y%N].k;
}

int main(){
    memset(ans,0x3f,sizeof(ans));
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=m;i++){
        int l,r,k;
        scanf("%d%d%d",&l,&r,&k);
        seg[i]={l,r,k};
        if(cal(l)==cal(r)){
            ans[i]=1e9;
            for(int j=l;j<=r;j++)
                ans[i]=min(ans[i],a[j]%k);
        }else if(k<B)
            v[k].push_back(i);
        else
            for(int j=0;j<=1e5;j+=k)
                ask.push_back(j/k*N+i);
    }
    for(int i=1;i<B;i++){
        if(v[i].empty())
            continue;
        build(1,1,n,i);
        for(int j:v[i])
            ans[j]=query(1,1,n,seg[j].l,seg[j].r);
    }
    sort(ask.begin(),ask.end(),cmp);
    for(int i=1;i<=n;i++)
        p[i]=make_pair(a[i],i);
    sort(p+1,p+n+1,greater<pair<int,int>>());
    memset(lmn,0x3f,sizeof(lmn));
    memset(rmn,0x3f,sizeof(rmn));
    memset(f,0x3f,sizeof(f));
    for(int i=0,j=1;i<ask.size();i++){
    	int val=ask[i]/N*seg[ask[i]%N].k; 
        while(j<=n && p[j].x>=val)
            add(p[j].y),j++;
        ans[ask[i]%N]=min(ans[ask[i]%N],Ask(seg[ask[i]%N].l,seg[ask[i]%N].r)-val);
    }
    for(int i=1;i<=m;i++)
        printf("%d\n",ans[i]);
    return 0;
}
